begin;
create table public.atlas_reasoning_snapshots(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),subject_id text not null,subject_type text not null,sequence_number bigint not null check(sequence_number>=0),occurred_at timestamptz not null,recorded_at timestamptz not null default now(),correlation_id uuid not null,input_hash text not null,engine_version text not null,rules_version text not null,payload jsonb not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id),unique(workspace_id,sequence_number));
create table public.atlas_reasoning_audits(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),snapshot_id uuid not null,sequence_number bigint not null check(sequence_number>=0),occurred_at timestamptz not null,recorded_at timestamptz not null default now(),correlation_id uuid not null,stage text not null,status text not null,artifact_ids text[] not null default '{}',payload jsonb not null default '{}',created_at timestamptz not null default now(),updated_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,foreign key(snapshot_id) references public.atlas_reasoning_snapshots(id),unique(workspace_id,domain_id),unique(workspace_id,sequence_number));
create table public.executive_signals(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),reasoning_snapshot_id uuid,category text not null,severity text not null,urgency text not null,title text not null,evidence jsonb not null default '[]',recommendation jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,foreign key(reasoning_snapshot_id) references public.atlas_reasoning_snapshots(id),unique(workspace_id,domain_id));
do $$declare t text;begin foreach t in array array['atlas_reasoning_snapshots','atlas_reasoning_audits','executive_signals'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using(public.is_active_workspace_member(workspace_id))',t||'_read',t);execute format('create policy %I on public.%I for insert to authenticated with check(public.is_active_workspace_member(workspace_id))',t||'_insert',t);end loop;end$$;
create policy executive_signals_update on public.executive_signals for update to authenticated using(public.is_active_workspace_member(workspace_id)) with check(public.is_active_workspace_member(workspace_id));
create trigger atlas_reasoning_snapshots_append_only before update or delete on public.atlas_reasoning_snapshots for each row execute function public.reject_append_only_mutation();create trigger atlas_reasoning_audits_append_only before update or delete on public.atlas_reasoning_audits for each row execute function public.reject_append_only_mutation();
grant select,insert on public.atlas_reasoning_snapshots,public.atlas_reasoning_audits to authenticated;grant select,insert,update on public.executive_signals to authenticated;revoke delete on all tables in schema public from authenticated;revoke all on all tables in schema public from anon;
create index atlas_reasoning_workspace_subject_idx on public.atlas_reasoning_snapshots(workspace_id,subject_id,sequence_number desc);create index atlas_reasoning_audit_snapshot_idx on public.atlas_reasoning_audits(workspace_id,snapshot_id,sequence_number);create index executive_signals_workspace_urgency_idx on public.executive_signals(workspace_id,urgency,created_at desc);
commit;
